1	using System.Diagnostics;
2	using Microsoft.AspNetCore.Mvc;
3	using HttpResults = Microsoft.AspNetCore.Http.Results;
4	
5	namespace TodoApi.Infrastructure.Extensions;
6	
7	public static class ResultExtensions
8	{
9	    private static int GetStatusCode(ErrorDefinition definition) => definition switch
10	    {
11	        ErrorDefinition.NotFound => StatusCodes.Status404NotFound,
12	        ErrorDefinition.Validation => StatusCodes.Status400BadRequest,
13	        ErrorDefinition.Conflict => StatusCodes.Status409Conflict,
14	        ErrorDefinition.Unauthorized => StatusCodes.Status401Unauthorized,
15	        _ => StatusCodes.Status500InternalServerError
16	    };
17	
18	    private static string GetProblemType(ErrorDefinition definition) => definition switch
19	    {
20	        ErrorDefinition.NotFound => "https://tools.ietf.org/html/rfc9110#section-15.5.5",
21	        ErrorDefinition.Validation => "https://tools.ietf.org/html/rfc9110#section-15.5.1",
22	        ErrorDefinition.Conflict => "https://tools.ietf.org/html/rfc9110#section-15.5.10",
23	        ErrorDefinition.Unauthorized => "https://tools.ietf.org/html/rfc9110#section-15.5.2",
24	        _ => "https://tools.ietf.org/html/rfc9110#section-15.6.1"
25	    };
26	
27	    private static string GetTitle(ErrorDefinition definition) => definition switch
28	    {
29	        ErrorDefinition.NotFound => "Resource Not Found",
30	        ErrorDefinition.Validation => "Validation Error",
31	        ErrorDefinition.Conflict => "Conflict",
32	        ErrorDefinition.Unauthorized => "Unauthorized",
33	        ErrorDefinition.Error => "Internal Server Error",
34	        _ => "An error occurred"
35	    };
36	
37	    public static IResult Match<T>(
38	        this Result<T> result,
39	        Func<T, IResult> onSuccess,
40	        Func<Result, IResult>? onFailure = null)
41	    {
42	        ArgumentNullException.ThrowIfNull(result);
43	        ArgumentNullException.ThrowIfNull(onSuccess);
44	
45	        return result.IsSuccess
46	            ? onSuccess(result.GetValue)
47	            : (onFailure ?? (r => r.ToProblemDetails()))(result);
48	    }
49	
50	    public static IResult ToOk<T>(this Result<T> result, Func<T, object>? mapper = null)
51	    {
52	        return result.Match(
53	            onSuccess: value => HttpResults.Ok(mapper?.Invoke(value) ?? value));
54	    }
55	
56	    public static IResult ToCreated<T>(this Result<T> result, string uri, Func<T, object>? mapper = null)
57	    {
58	        return result.Match(
59	            onSuccess: value => HttpResults.Created(uri, mapper?.Invoke(value) ?? value));
60	    }
61	
62	    public static IResult ToCreated<T>(
63	        this Result<T> result,
64	        Func<T, string> uriFactory,
65	        Func<T, object>? mapper = null)
66	    {
67	        ArgumentNullException.ThrowIfNull(uriFactory);
68	
69	        return result.Match(
70	            onSuccess: value => HttpResults.Created(uriFactory(value), mapper?.Invoke(value) ?? value));
71	    }
72	
73	    public static IResult ToAccepted<T>(this Result<T> result, string uri, Func<T, object>? mapper = null)
74	    {
75	        return result.Match(
76	            onSuccess: value => HttpResults.Accepted(uri, mapper?.Invoke(value) ?? value));
77	    }
78	
79	    public static IResult ToNoContent<T>(this Result<T> result)
80	    {
81	        return result.Match(
82	            onSuccess: _ => HttpResults.NoContent());
83	    }
84	
85	    public static IResult ToNoContent(this Result result)
86	    {
87	        ArgumentNullException.ThrowIfNull(result);
88	
89	        return result.IsSuccess
90	            ? HttpResults.NoContent()
91	            : result.ToProblemDetails();
92	    }
93	
94	    public static IResult ToProblemDetails(this Result result)
95	    {
96	        ArgumentNullException.ThrowIfNull(result);
97	
98	        if (result.IsSuccess)
99	        {
100	            throw new InvalidOperationException("Cannot create problem details from a successful result.");
101	        }
102	
103	        var error = result.Error;
104	        var statusCode = GetStatusCode(error.Definition);
105	        var traceId = Activity.Current?.Id;
106	
107	        if (error.Definition == ErrorDefinition.Validation)
108	        {
109	            return HttpResults.Problem(BuildValidationProblem(error, statusCode, traceId));
110	        }
111	
112	        var problemDetails = new ProblemDetails
113	        {
114	            Type = GetProblemType(error.Definition),
115	            Title = GetTitle(error.Definition),
116	            Status = statusCode,
117	            Detail = error.Description,
118	        };
119	
120	        problemDetails.Extensions["code"] = error.Code;
121	        if (traceId is not null)
122	        {
123	            problemDetails.Extensions["traceId"] = traceId;
124	        }
125	
126	        return HttpResults.Problem(problemDetails);
127	    }
128	
129	    private static ValidationProblemDetails BuildValidationProblem(
130	        ErrorResult error,
131	        int statusCode,
132	        string? traceId)
133	    {
134	        var errors =
135	            error.Metadata is { } metadata
136	            && metadata.TryGetValue("Errors", out var raw)
137	            && raw is Dictionary<string, string[]> map
138	                ? map
139	                : new Dictionary<string, string[]>(StringComparer.Ordinal);
140	
141	        var problem = new ValidationProblemDetails(errors)
142	        {
143	            Type = GetProblemType(error.Definition),
144	            Title = GetTitle(error.Definition),
145	            Status = statusCode,
146	            Detail = error.Description,
147	        };
148	
149	        problem.Extensions["code"] = error.Code;
150	        if (traceId is not null)
151	        {
152	            problem.Extensions["traceId"] = traceId;
153	        }
154	
155	        return problem;
156	    }
157	}
