5	/// <summary>
6	/// Wolverine middleware that logs command and query execution.
7	/// Applied to all handlers via policy configuration.
8	/// Implements cross-cutting concern logging pattern.
9	/// Uses Envelope to access message information without resolving 'object' type.
10	/// </summary>
11	public sealed class LoggingMiddleware
12	{
13	    public void Before(Envelope envelope, ILogger<LoggingMiddleware> logger)
14	        => logger.ExecutingMessage(envelope.MessageType ?? "Unknown");
15	
16	    public void After(Envelope envelope, ILogger<LoggingMiddleware> logger)
17	        => logger.CompletedMessage(envelope.MessageType ?? "Unknown");
