        await context.SaveChangesAsync(ct).ConfigureAwait(false);

        logger.LogTodoItemAdded(todoList.Id, item.Name);

        return Result.Success(
            new AddTodoItemResponse(item.Id, todoList.Id, item.Name, item.IsComplete)
        );
    }
}

